from typing import Union, Any


class ASTNode:
    def __init__(self, node_type: str, **kwargs):
        self.type: str = node_type
        if node_type == "number":
            self.value: float = kwargs.get("value")
        elif node_type == "binop":
            self.op: str = kwargs.get("op")
            self.left: ASTNode = kwargs.get("left")
            self.right: ASTNode = kwargs.get("right")
        elif node_type == "unary":
            self.op: str = kwargs.get("op")
            self.operand: ASTNode = kwargs.get("operand")


def __repr__(self) -> str:
    if self.type == "number":
        return f"Number({self.value})"
    elif self.type == "binop":
        return f"BinOp({self.op}, {self.left}, {self.right})"
    elif self.type == "unary":
        return f"UnaryOp({self.op}, {self.operand})"
    return "ASTNode()"


def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty expression")

    tokens = _tokenize(expression)
    return _parse_expression(tokens)


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val

    raise ValueError("Invalid AST node")


def _tokenize(expression: str) -> list:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c == " ":
            i += 1
            continue

        if c in "()+-*/":
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == ".":
            j = i
            while j < n and (expression[j].isdigit() or expression[j] == "."):
                j += 1
            num_str = expression[i:j]
            try:
                num = float(num_str)
                tokens.append(num)
            except ValueError:
                raise ValueError(f"Invalid number: {num_str}")
            i = j
        else:
            raise ValueError(f"Invalid token: {c}")

    return tokens


def _parse_expression(tokens: list) -> ASTNode:
    return _parse_additive(tokens)


def _parse_additive(tokens: list) -> ASTNode:
    left = _parse_multiplicative(tokens)

    while tokens and tokens[0] in ("+", "-"):
        op = tokens.pop(0)
        right = _parse_multiplicative(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def _parse_multiplicative(tokens: list) -> ASTNode:
    left = _parse_unary(tokens)

    while tokens and tokens[0] in ("*", "/"):
        op = tokens.pop(0)
        right = _parse_unary(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def _parse_unary(tokens: list) -> ASTNode:
    if tokens and tokens[0] == "-":
        op = tokens.pop(0)
        operand = _parse_primary(tokens)
        return ASTNode("unary", op=op, operand=operand)

    return _parse_primary(tokens)


def _parse_primary(tokens: list) -> ASTNode:
    if not tokens:
        raise ValueError("Unexpected end of expression")

    token = tokens[0]

    if token == "(":
        tokens.pop(0)
        node = _parse_expression(tokens)
        if not tokens or tokens[0] != ")":
            raise ValueError("Unmatched parentheses")
        tokens.pop(0)
        return node
    elif isinstance(token, (int, float)):
        tokens.pop(0)
        return ASTNode("number", value=token)
    else:
        raise ValueError(f"Unexpected token: {token}")
